import React from "react";

function MyPredictionHistory() {
  return (
    <div>
      <h2>My Prediction History</h2>
      <p>Total Predictions: 0</p>

      <h3>Recent 5 Predictions</h3>
      <table border="1">
        <tr>
          <th>Date</th>
          <th>Role</th>
          <th>Experience</th>
          <th>Salary</th>
        </tr>
      </table>

      <button>View Full History</button>
    </div>
  );
}

export default MyPredictionHistory;
